# In real code: response.raise_for_status() crashes on any 4xx/5xx.
# We simulate it here with a class that mimics httpx.Response.

class FakeResponse:
    def __init__(self, status, body):
        self.status_code = status
        self._body = body

    def json(self):
        return self._body

    def raise_for_status(self):
        if 400 <= self.status_code < 600:
            raise RuntimeError(f"HTTP {self.status_code}")

responses = [
    FakeResponse(200, {"id": 7}),
    FakeResponse(429, {"error": "rate limited", "retry_after": 1}),
    FakeResponse(500, {"error": "internal"}),
]

for r in responses:
    try:
        r.raise_for_status()
        print("ok:", r.json())
    except RuntimeError as err:
        if r.status_code >= 500:
            print(f"retry-worthy: {err}")
        else:
            print(f"caller bug: {err} body={r.json()}")

def handle(status):
    if 200 <= status < 300:
        return "ok"
    if status == 404:
        return "not-found"
    if status >= 500:
        return "retry"
    return "client-bug"

for s in [200, 404, 401, 503]:
    print(handle(s))

class FakeResponse:
    def raise_for_status(self):
        if 400 <= self.status_code < 600:
            raise RuntimeError(f"HTTP {self.status_code}")

r = FakeResponse(); r.status_code = 404
try:
    r.___()
except RuntimeError as err:
    print(f"caught: {err}")

