steps.solution:
def classify(status):
    if 200 <= status < 300:
        return "success"
    if 400 <= status < 500:
        return "client-error"
    if 500 <= status < 600:
        return "server-error"
    return "other"

for code in [200, 404, 503, 301, 100]:
    print(classify(code))

def safe_fetch(response):
    status = response["status"]
    if 200 <= status < 300:
        return response["body"]
    if status == 404:
        return "not found"
    if 400 <= status < 500:
        return "client error"
    if 500 <= status < 600:
        return "retry later"
    raise ValueError(f"unexpected status: {status}")

responses = [
    {"status": 200, "body": {"id": 7}},
    {"status": 404, "body": {"error": "user not found"}},
    {"status": 401, "body": {"error": "auth required"}},
    {"status": 503, "body": {"error": "down for maintenance"}},
]

for r in responses:
    print(safe_fetch(r))
